parameters.jsCode:
const items = $input.all();
const results = [];
const skipDomains = ['pinterest', 'facebook.com', 'twitter.com', 'instagram.com', 'tiktok.com', 'reddit.com'];

for (const item of items) {
  const searchResults = item.json.items || [];
  const queryQ = item.json.queries?.request?.[0]?.searchTerms || '';

  let sourceType = 'academic';
  if (queryQ.includes('vocabulario') || queryQ.includes('vocabulary') || queryQ.includes('frases') || queryQ.includes('learning')) sourceType = 'vocabulary';
  if (queryQ.includes('noticias') || queryQ.includes('news')) sourceType = 'news';

  for (const r of searchResults) {
    const url = r.link || '';
    if (skipDomains.some(d => url.includes(d))) continue;
    results.push({
      json: {
        title: r.title || '',
        url,
        snippet: r.snippet || '',
        source_type: sourceType,
        display_link: r.displayLink || ''
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { _empty: true } }];

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const raw = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
    const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const analysis = JSON.parse(clean);

    if (analysis.relevant === true && (analysis.relevance_score || 0) >= 7) {
      results.push({
        json: {
          title: item.json.title || '',
          url: item.json.url || '',
          source_type: analysis.content_type || item.json.source_type || 'other',
          language: analysis.language || 'general',
          summary: analysis.summary || '',
          relevance_score: analysis.relevance_score || 7,
          tags: analysis.tags || [],
          display_link: item.json.display_link || ''
        }
      });
    }
  } catch (e) {
    // JSON malformado de Gemini, ignorar
  }
}

return results.length > 0 ? results : [{ json: { _skip: true } }];

